def ui_px(base_size, scale=None):
    s = UI_FONT_SCALE if scale is None else scale
    return max(1, round(base_size * s))

def load_embedded_font():
    """Load the embedded Manrope font from base64 data in memory.
    Returns the font family name if successful, otherwise None."""
    try:
        font_data = base64.b64decode(MANROPE_TTF_B64)
        font_id = QFontDatabase.addApplicationFontFromData(font_data)
        if font_id >= 0:
            families = QFontDatabase.applicationFontFamilies(font_id)
            if families:
                return families[0]
    except Exception:
        pass
    return None

def load_app_font(point_size=10):
    """Load Manrope from embedded font data, else system Manrope, else Segoe UI."""
    embedded_family = load_embedded_font()
    if embedded_family:
        font = QFont(embedded_family, point_size)
        font.setWeight(QFont.Weight.DemiBold)
        return font
    families = QFontDatabase.families()
    if _FONT_FAMILY in families:
        font = QFont(_FONT_FAMILY, point_size)
        font.setWeight(QFont.Weight.DemiBold)
        return font
    return QFont("Segoe UI", point_size)


