class ScrollPresetField(QLineEdit):
    """Read-only field: scroll wheel cycles through preset values."""

    value_changed = Signal()
    FOCUS_CLEAR_MS = 500

    def __init__(
        self,
        values,
        default=None,
        width=_SCROLL_FIELD_W,
        height=_SCROLL_FIELD_H,
        parent=None,
    ):
        super().__init__(parent)
        self._values = list(values)
        if not self._values:
            raise ValueError("values must not be empty")
        if default is not None and default in self._values:
            self._index = self._values.index(default)
        else:
            self._index = 0
        self.setObjectName("ScrollPresetField")
        self.setAttribute(Qt.WidgetAttribute.WA_StyledBackground, True)
        self.setReadOnly(True)
        self.setFocusPolicy(Qt.FocusPolicy.NoFocus)
        self.setAlignment(Qt.AlignmentFlag.AlignCenter)
        self.setSizePolicy(QSizePolicy.Policy.Fixed, QSizePolicy.Policy.Fixed)
        self.setFixedSize(width, height)
        self.setToolTip("Scroll to change")
        self._scroll_highlighted = False
        self._highlight_timer = QTimer(self)
        self._highlight_timer.setSingleShot(True)
        self._highlight_timer.timeout.connect(self._clear_scroll_highlight)
        self.apply_field_style(False)
        self._refresh_display()

    def _field_font_px(self):
        win = self.window()
        if hasattr(win, "_controls_font_px"):
            return win._controls_font_px()
        return ui_px(11, getattr(win, "_font_scale", UI_FONT_SCALE))

    def apply_field_style(self, highlighted=None):
        if highlighted is not None:
            self._scroll_highlighted = highlighted
        border_color = _CLR_RED if self._scroll_highlighted else _CLR_FIELD_BORDER
        body = self._field_font_px()
        self.setStyleSheet(
            f"background-color: {_CLR_FIELD_BG};"
            f"color: {_CLR_TEXT};"
            f"font-weight: 600;"
            f"border: 1px solid {border_color};"
            f"border-radius: {_CLR_FIELD_RADIUS}px;"
            f"padding: 3px 8px;"
            f"font-size: {body}px;"
            f"outline: none;"
        )

    def _clear_scroll_highlight(self):
        self.apply_field_style(False)

    def _highlight_from_scroll(self):
        self.apply_field_style(True)
        self._highlight_timer.start(self.FOCUS_CLEAR_MS)

    def mousePressEvent(self, event):
        event.accept()

    def value(self):
        return self._values[self._index]

    def set_value(self, value):
        if value in self._values:
            self._index = self._values.index(value)
            self._refresh_display()

    def _refresh_display(self):
        self.setText(str(self._values[self._index]))

    def wheelEvent(self, event):
        delta = event.angleDelta().y()
        if delta > 0:
            self._index = (self._index - 1) % len(self._values)
        elif delta < 0:
            self._index = (self._index + 1) % len(self._values)
        else:
            super().wheelEvent(event)
            return
        self._refresh_display()
        self.value_changed.emit()
        self._highlight_from_scroll()
        event.accept()


class HotbarDetector:
    def __init__(self):
        self.hotbar_region = {
            'left': 600,
            'top': 933,
            'width': 1320 - 600,
            'height': 1020 - 933,
        }
        self.num_slots = 9
        self.slot_width = self.hotbar_region['width'] / self.num_slots

    def capture_hotbar(self):
        try:
            with mss() as sct:
                screenshot = sct.grab(self.hotbar_region)
                img = np.array(screenshot)
                img = cv2.cvtColor(img, cv2.COLOR_BGRA2BGR)
                return img
        except Exception as e:
            print(f"Error capturing hotbar: {e}")
            return None

    def find_selected_slot(self, img):
        gray = cv2.cvtColor(img, cv2.COLOR_BGR2GRAY)
        _, thresh = cv2.threshold(gray, 200, 255, cv2.THRESH_BINARY)
        max_brightness = 0
        selected_slot = -1
        for slot_idx in range(self.num_slots):
            slot_x_start = int(slot_idx * self.slot_width)
            slot_x_end = int((slot_idx + 1) * self.slot_width)
            top_edge = thresh[0:8, slot_x_start:slot_x_end]
            bottom_edge = thresh[-8:, slot_x_start:slot_x_end]
            if slot_x_start < thresh.shape[1] and slot_x_end <= thresh.shape[1]:
                left_edge = thresh[:, slot_x_start:min(slot_x_start+5, slot_x_end)]
                right_edge = thresh[:, max(slot_x_start, slot_x_end-5):slot_x_end]
                total_brightness = (np.sum(top_edge) + np.sum(bottom_edge) +
                                    np.sum(left_edge) + np.sum(right_edge))
                if total_brightness > max_brightness and total_brightness > 2000:
                    max_brightness = total_brightness
                    selected_slot = slot_idx
        return selected_slot

    def analyze_slot(self, img, slot_idx):
        if slot_idx < 0 or slot_idx >= self.num_slots:
            return (False, 0)
        slot_x_start = int(slot_idx * self.slot_width)
        slot_x_end = int((slot_idx + 1) * self.slot_width)
        full_slot = img[:, slot_x_start:slot_x_end]
        h, w = full_slot.shape[:2]
        center_y_start = int(h * 0.25)
        center_y_end = int(h * 0.75)
        center_x_start = int(w * 0.25)
        center_x_end = int(w * 0.75)
        center_region = full_slot[center_y_start:center_y_end, center_x_start:center_x_end]
        if center_region.size == 0:
            return (False, 0)
        gray = cv2.cvtColor(center_region, cv2.COLOR_BGR2GRAY)
        variance = np.var(gray)
        has_block = variance > 1000
        return (has_block, variance)

    def analyze_all_slots(self, img):
        results = []
        for i in range(self.num_slots):
            has_block, variance = self.analyze_slot(img, i)
            results.append((has_block, variance))
        return results

    def check_any_slot_has_block(self):
        img = self.capture_hotbar()
        if img is None:
            return False, 0
        results = self.analyze_all_slots(img)
        for has_block, variance in results:
            if has_block:
                return True, variance
        return False, 0

    def count_block_slots(self):
        img = self.capture_hotbar()
        if img is None:
            return 0
        results = self.analyze_all_slots(img)
        return sum(1 for has_block, _ in results if has_block)

    def scroll_to_block_slot(self, mouse_ctrl):
        img = self.capture_hotbar()
        if img is None:
            return False

        results = self.analyze_all_slots(img)
        block_indices = [i for i, (has_block, _) in enumerate(results) if has_block]
        if not block_indices:
            return False

        selected = self.find_selected_slot(img)
        if selected == -1:
            selected = 0

        if selected in block_indices:
            return True

        # Prefer the block reachable in the fewest scroll steps (shortest path on 1–9 ring).
        n = self.num_slots
        target_idx = min(
            block_indices,
            key=lambda idx: min((idx - selected) % n, (selected - idx) % n),
        )

        # Minecraft selects hotbar via keys 1–9; wheel scroll often fails after /order or chat focus.
        pyautogui.press(str(target_idx + 1))
        time.sleep(0.12)
        key_img = self.capture_hotbar()
        if key_img is not None:
            if self.find_selected_slot(key_img) == target_idx:
                return True
            has_b, _ = self.analyze_slot(key_img, target_idx)
            if has_b:
                return True

        # scroll(0, -1) moves selection toward the next slot to the right (index +1 mod n).
        # scroll(0, 1) moves toward the left (index -1 mod n).
        max_moves = n + 2
        for _ in range(max_moves):
            current_img = self.capture_hotbar()
            if current_img is None:
                return False
            current_selected = self.find_selected_slot(current_img)
            if current_selected == -1:
                current_selected = selected
            if current_selected == target_idx:
                return True

            forward = (target_idx - current_selected) % n
            backward = (current_selected - target_idx) % n
            if forward <= backward:
                mouse_ctrl.scroll(0, -1)
            else:
                mouse_ctrl.scroll(0, 1)
            time.sleep(0.2)

        final_img = self.capture_hotbar()
        if final_img is None:
            return False
        final_selected = self.find_selected_slot(final_img)
        return final_selected == target_idx


class InventoryDetector:
    def __init__(self):
        self.x1 = 635
        self.y1 = 255
        self.x2 = 1283
        self.y2 = 473

        self.order_x1 = 635
        self.order_y1 = 146
        self.order_x2 = 1283
        self.order_y2 = 364

        self.bp_x1 = 635
        self.bp_y1 = 525
        self.bp_x2 = 1283
        self.bp_y2 = 743

        self.threshold = 20
        self.book_template = None
        self.hijau_template = None
        self.order_template = None
        self.paper_template = None
        self.paper_template_gray = None
        self.paper_match_threshold = 0.6

        self.load_templates()

    def load_templates(self):
        try:
            self.book_template = imdecode_from_base64(BOOK_PNG_B64)
        except Exception as e:
            print(f"Error loading book template: {e}")
        try:
            self.hijau_template = imdecode_from_base64(HIJAU_PNG_B64)
        except Exception as e:
            print(f"Error loading hijau template: {e}")
        try:
            self.order_template = imdecode_from_base64(ORDER_PNG_B64)
        except Exception as e:
            print(f"Error loading order template: {e}")
        try:
            self.paper_template = imdecode_from_base64(PAPER_PNG_B64)
            if self.paper_template is not None:
                if len(self.paper_template.shape) == 3 and self.paper_template.shape[2] == 4:
                    self.paper_template = cv2.cvtColor(self.paper_template, cv2.COLOR_BGRA2BGR)
                self.paper_template_gray = cv2.cvtColor(self.paper_template, cv2.COLOR_BGR2GRAY)
        except Exception as e:
            print(f"Error loading paper template: {e}")

    def detect_template_on_screen(self, template, threshold=0.8, bbox=(600, 250, 1300, 760)):
        if template is None:
            return False
        try:
            screenshot = ImageGrab.grab(bbox=bbox)
            screenshot_np = np.array(screenshot)
            screenshot_cv = cv2.cvtColor(screenshot_np, cv2.COLOR_RGB2BGR)
            if len(template.shape) == 3 and template.shape[2] == 4:
                template_bgr = cv2.cvtColor(template, cv2.COLOR_BGRA2BGR)
            else:
                template_bgr = template
            if (template_bgr.shape[0] > screenshot_cv.shape[0] or
                    template_bgr.shape[1] > screenshot_cv.shape[1]):
                return False
            result = cv2.matchTemplate(screenshot_cv, template_bgr, cv2.TM_CCOEFF_NORMED)
            _, max_val, _, _ = cv2.minMaxLoc(result)
            return max_val >= threshold
        except Exception as e:
            print(f"Template detection error: {e}")
            return False

    def detect_book_on_screen(self):
        return self.detect_template_on_screen(self.book_template, 0.8)

    def detect_hijau_on_screen(self):
        return self.detect_template_on_screen(self.hijau_template, 0.8)

    def detect_order_on_screen(self):
        return self.detect_template_on_screen(self.order_template, 0.8)

    def capture_region(self, x1, y1, x2, y2):
        try:
            screenshot = ImageGrab.grab(bbox=(x1, y1, x2, y2))
            screenshot_np = np.array(screenshot)
            screenshot_cv = cv2.cvtColor(screenshot_np, cv2.COLOR_RGB2BGR)
            return screenshot_cv
        except Exception as e:
            print(f"Capture error: {e}")
            return None

    def detect_paper_in_slot(self, slot_roi):
        if self.paper_template is None or self.paper_template_gray is None or slot_roi.size == 0:
            return False, 0.0
        try:
            template_h, template_w = self.paper_template.shape[:2]
            if slot_roi.shape[0] < template_h * 0.5 or slot_roi.shape[1] < template_w * 0.5:
                return False, 0.0
            slot_gray = cv2.cvtColor(slot_roi, cv2.COLOR_BGR2GRAY)
            scales = [0.5, 0.6, 0.7, 0.8, 0.9, 1.0, 1.1, 1.2, 1.3, 1.4, 1.5]
            max_confidence = 0.0
            for scale in scales:
                width = int(self.paper_template_gray.shape[1] * scale)
                height = int(self.paper_template_gray.shape[0] * scale)
                if width > slot_gray.shape[1] or height > slot_gray.shape[0]:
                    continue
                if width < 5 or height < 5:
                    continue
                scaled_template = cv2.resize(self.paper_template_gray, (width, height))
                result = cv2.matchTemplate(slot_gray, scaled_template, cv2.TM_CCOEFF_NORMED)
                _, max_val, _, _ = cv2.minMaxLoc(result)
                if max_val > max_confidence:
                    max_confidence = max_val
            is_paper = max_confidence >= self.paper_match_threshold
            return is_paper, max_confidence
        except Exception:
            return False, 0.0

    def find_slot_rects(self, img):
        """Find inventory slot rectangles (sorted top-left, max 27)."""
        gray = cv2.cvtColor(img, cv2.COLOR_BGR2GRAY)
        blurred = cv2.GaussianBlur(gray, (5, 5), 0)
        edges = cv2.Canny(blurred, 50, 150)
        contours, _ = cv2.findContours(edges, cv2.RETR_EXTERNAL, cv2.CHAIN_APPROX_SIMPLE)
        slots = []
        for contour in contours:
            peri = cv2.arcLength(contour, True)
            approx = cv2.approxPolyDP(contour, 0.04 * peri, True)
            if len(approx) != 4:
                continue
            x, y, w, h = cv2.boundingRect(approx)
            aspect_ratio = w / float(h)
            if 0.7 < aspect_ratio < 1.3 and 10 < w < 150 and 10 < h < 150:
                slots.append((x, y, w, h))
        return sorted(slots, key=lambda s: (s[1], s[0]))

    def classify_slot_for_count(self, slot_roi):
        has_paper, _ = self.detect_paper_in_slot(slot_roi)
        if has_paper or np.std(slot_roi) < self.threshold:
            return "empty"
        return "filled"

    def is_filled_click_target(self, slot_roi):
        has_paper, _ = self.detect_paper_in_slot(slot_roi)
        if has_paper:
            return False
        gray_roi = cv2.cvtColor(slot_roi, cv2.COLOR_BGR2GRAY)
        return np.var(gray_roi) > 1000

    def analyze_slots(self, img):
        """Count empty/filled slots and return per-slot state for overlay drawing."""
        if img is None:
            return 0, 0, []
        try:
            empty_count = 0
            filled_count = 0
            analyzed = []
            for x, y, w, h in self.find_slot_rects(img)[:27]:
                slot_roi = img[y:y + h, x:x + w]
                if slot_roi.size == 0:
                    continue
                state = self.classify_slot_for_count(slot_roi)
                analyzed.append((x, y, w, h, state))
                if state == "empty":
                    empty_count += 1
                else:
                    filled_count += 1
            return empty_count, filled_count, analyzed
        except Exception as e:
            print(f"analyze_slots error: {e}")
            return 0, 0, []

    def detect_slots(self, img):
        empty_count, filled_count, _ = self.analyze_slots(img)
        return empty_count, filled_count

    def draw_slot_overlay(self, img, analyzed):
        output = img.copy()
        for x, y, w, h, state in analyzed:
            color = (0, 255, 0) if state == "empty" else (0, 0, 255)
            cv2.rectangle(output, (x, y), (x + w, y + h), color, 2)
        return output

    def get_empty_slot_count(self):
        img = self.capture_region(self.x1, self.y1, self.x2, self.y2)
        empty, _ = self.detect_slots(img)
        return empty

    def _filled_clicks_from_image(self, img, region_x1, region_y1):
        clicks = []
        for x, y, w, h in self.find_slot_rects(img)[:27]:
            slot_roi = img[y:y + h, x:x + w]
            if slot_roi.size == 0:
                continue
            if self.is_filled_click_target(slot_roi):
                clicks.append((region_x1 + x + w // 2, region_y1 + y + h // 2))
        return clicks

    def get_backpack_filled_clicks(self):
        img = self.capture_region(self.bp_x1, self.bp_y1, self.bp_x2, self.bp_y2)
        if img is None:
            return []
        try:
            return self._filled_clicks_from_image(img, self.bp_x1, self.bp_y1)
        except Exception as e:
            print(f"get_backpack_filled_clicks error: {e}")
            return []

    def get_filled_clicks_in_region(self, x1, y1, x2, y2):
        img = self.capture_region(x1, y1, x2, y2)
        if img is None:
            return []
        try:
            return self._filled_clicks_from_image(img, x1, y1)
        except Exception as e:
            print(f"get_filled_clicks_in_region error: {e}")
            return []

class BotSignals(QObject):
    update_status = Signal(str, str)
    
class HotbarSignals(QObject):
    update_labels = Signal(int, list)
    update_display = Signal(np.ndarray)
    show_waiting = Signal()

class ChestSignals(QObject):
    mode_changed = Signal(str, str)
    status_changed = Signal(str)
    update_display = Signal(int, int, np.ndarray)
    reset_display = Signal()

class MainWindow(QMainWindow):
    HOTBAR_CAPTURE_W = 1320 - 600
    HOTBAR_CAPTURE_H = 1020 - 933
    HOTBAR_PREVIEW_W = 360
    HOTBAR_PREVIEW_H = round(HOTBAR_CAPTURE_H * HOTBAR_PREVIEW_W / HOTBAR_CAPTURE_W)
    CHEST_PREVIEW_H = 121
    # --- Hotbar green/red box shape (coordinates are on the 720×87 MSS capture) ---
    # True  = 1:1 squares (width == height), centered in each slot column.
    # False = full-height rectangles; use INSET_Y_* to change height (not 1:1).
    HOTBAR_BOX_1_TO_1 = True
    HOTBAR_BOX_INSET_X = 4          # horizontal padding inside each slot (both modes)
    HOTBAR_BOX_INSET_Y_TOP = 4      # only when HOTBAR_BOX_1_TO_1 is False
    HOTBAR_BOX_INSET_Y_BOTTOM = 4   # only when HOTBAR_BOX_1_TO_1 is False
    HOTBAR_BOX_Y_OFFSET = 0         # only when 1:1: move square down (+) or up (-)
    HOTBAR_BOX_THICKNESS = 1
    HOTBAR_BOX_THICKNESS_SELECTED = 3
    # Hotbar preview only appears when any slot reaches this variance.
    HOTBAR_MIN_VARIANCE_TO_SHOW = 4359
    WINDOW_SPAWN_X = 1150
    WINDOW_SPAWN_Y = 209

    def __init__(self):
        super().__init__()
        self.setWindowTitle("Auto")
        self.setWindowIcon(QIcon(resource_path('auto.ico')))
        self.setWindowFlags(
            Qt.WindowStaysOnTopHint | Qt.FramelessWindowHint | Qt.Tool
        )
        self.setAttribute(Qt.WA_TranslucentBackground)
        self._drag_pos = None
        self._font_scale = UI_FONT_SCALE
        self._ch_status_color = _CLR_RED
        self._ch_status_dot_large = False
        self._stat_title_labels = []
        self._dot_anim_index = 0
        self._dot_anim_timer = QTimer(self)
        self._dot_anim_timer.timeout.connect(self._animate_dot)
        self._dot_anim_timer.start(500)
        self._hotbar_scanning_text = False
        self._chest_scanning_text = False

        main_widget = QWidget()
        main_widget.setAttribute(Qt.WA_TranslucentBackground)
        self.setCentralWidget(main_widget)
        main_layout = QVBoxLayout(main_widget)
        main_layout.setSpacing(0)
        main_layout.setContentsMargins(6, 6, 6, 6)

        self._shutdown_done = False
        self._book_loop_running = True
        self.setup_main_panel(main_layout)
        self._install_middle_click_close(main_widget)

        main_layout.setSizeConstraint(QVBoxLayout.SetFixedSize)

        self.adjustSize()
        self.setFixedSize(self.width(), self.height())
        self.move(self.WINDOW_SPAWN_X, self.WINDOW_SPAWN_Y)

        self.detector = InventoryDetector()
        self.hotbar_detector = HotbarDetector()
        self.mouse = mouse.Controller()

        self.running = False
        self.stop_requested = False

        self.bot_signals = BotSignals()
        self.bot_signals.update_status.connect(self.update_status)

        try:
            keyboard.add_hotkey('ctrl+o', self.toggle_automation)
        except Exception as e:
            print(f"Warning: Could not register hotkeys: {e}")

        # Start detector threads
        self.hotbar_running = True
        self.hotbar_thread = threading.Thread(target=self.hotbar_detection_loop, daemon=True)
        self.hotbar_thread.start()

        self.chest_monitoring = False
        # Main-thread only: drop stale ch_update_display events queued after we reset (MODE N/A).
        self._accept_chest_preview_updates = False
        self.chest_active_region = 'chest'
        self.chest_book_thread = threading.Thread(target=self.book_detection_loop, daemon=True)
        self.chest_book_thread.start()

        QTimer.singleShot(0, self._defocus_price_input)

    def _defocus_price_input(self):
        self.price_input.clearFocus()
        self.order_input.clearFocus()
        if hasattr(self, "_panel_group"):
            self._panel_group.setFocus(Qt.FocusReason.OtherFocusReason)

    def _ui_px(self, base_size):
        return ui_px(base_size, self._font_scale)

    def _controls_font_px(self):
        return self._ui_px(11)

    def _control_label_stylesheet(self):
        return (
            f"font-size: {self._controls_font_px()}px; font-weight: 600; "
            f"color: {_CLR_TEXT};"
        )

    def _apply_ui_scale(self):
        scale = self._font_scale
        self.setFont(load_app_font(self._ui_px(10)))
        self.setStyleSheet(build_stylesheet(scale))
        if hasattr(self, "price_input"):
            field_w = self._ui_px(_SCROLL_FIELD_W)
            field_h = self._ui_px(_SCROLL_FIELD_H)
            self.price_input.setFixedSize(field_w, field_h)
            self.order_input.setFixedSize(field_w, field_h)
            self.price_input.apply_field_style()
            self.order_input.apply_field_style()
        if hasattr(self, "price_label"):
            self.price_label.setStyleSheet(self._control_label_stylesheet())
            self.order_label.setStyleSheet(self._control_label_stylesheet())
        if hasattr(self, "status_label"):
            self.status_label.setStyleSheet(self._status_label_stylesheet())
            self.progress_label.setStyleSheet(self._progress_label_stylesheet())
            if self._ch_status_dot_large:
                self.ch_status_val.setStyleSheet(
                    self._status_dot_active_stylesheet(self._ch_status_color)
                )
            else:
                self.ch_status_val.setStyleSheet(self._status_dot_stylesheet())
            for title_label in self._stat_title_labels:
                title_label.setStyleSheet(self._stat_title_stylesheet())
            preview_style = self._preview_label_stylesheet()
            if hasattr(self, "preview_wait_label"):
                self.preview_wait_label.setStyleSheet(preview_style)
            self.hotbar_img_label.setStyleSheet(preview_style)
            self.chest_img_label.setStyleSheet(preview_style)
            self._refresh_stat_value_styles()
        self.adjustSize()
        self.setFixedSize(self.width(), self.height())

    def _status_label_stylesheet(self):
        return (
            f"font-weight: 600; color: {_CLR_TEXT}; font-size: {self._ui_px(11)}px;"
        )

    def _progress_label_stylesheet(self):
        return f"color: {_CLR_TEXT}; font-size: {self._ui_px(11)}px;"

    def _stat_title_stylesheet(self):
        return (
            f"font-size: {self._ui_px(11)}px; font-weight: 600; color: {_CLR_TEXT};"
        )

    def _preview_label_stylesheet(self):
        return (
            f"background: transparent; color: {_CLR_TEXT}; "
            f"font-size: {self._ui_px(11)}px;"
        )

    def _status_dot_stylesheet(self, color=None):
        color = self._ch_status_color if color is None else color
        return f"color: {color}; font-size: {self._ui_px(11)}px;"

    def _status_dot_active_stylesheet(self, color):
        return f"color: {color}; font-size: {self._ui_px(16)}px;"

    def _stat_value_stylesheet(self, value):
        if isinstance(value, str):
            text = value.strip()
            if not text or text.upper() == "N/A":
                has_value = False
            else:
                try:
                    has_value = float(text) != 0
                except ValueError:
                    has_value = True
        else:
            has_value = int(value) != 0
        color = _CLR_RED if has_value else _CLR_TEXT
        return (
            f"color: {color}; font-size: {self._ui_px(14)}px; font-weight: 600;"
        )

    def _refresh_stat_value_styles(self):
        for label in (
            self.ch_empty_val,
            self.ch_filled_val,
            self.ch_total_val,
            self.ch_mode_val,
            self.hb_var_val,
        ):
            self._set_stat_value(label, label.text())

    def _change_font_scale(self, delta_y):
        if delta_y == 0:
            return
        step = UI_FONT_SCALE_STEP if delta_y > 0 else -UI_FONT_SCALE_STEP
        self._font_scale = max(
            UI_FONT_SCALE_MIN,
            min(UI_FONT_SCALE_MAX, round(self._font_scale + step, 2)),
        )
        self._apply_ui_scale()

    def _sell_price_for_command(self):
        return f"{self.price_input.value()}k"

