    def _add_info_block(self, layout, title, val_label, add_divider=True):
        vbox = QVBoxLayout()
        vbox.setSpacing(0)
        t_label = QLabel(title)
        self._stat_title_labels.append(t_label)
        t_label.setAlignment(Qt.AlignCenter)
        val_label.setAlignment(Qt.AlignCenter)
        vbox.addWidget(t_label)
        vbox.addWidget(val_label)
